// Parse Meta Cloud API webhook payload
const body = $input.first().json.body || $input.first().json;

const entry = body.entry?.[0];
const changes = entry?.changes?.[0];
const value = changes?.value;
const message = value?.messages?.[0];
const contact = value?.contacts?.[0];

if (!message) {
  return [{ json: { skip: true, reason: 'No message in payload' } }];
}

const msgId = message.id;
const phone = message.from;
const contactName = contact?.profile?.name || phone;
const type = message.type || 'text';
let content = message.text?.body || message.caption || '';
let mediaUrl = null;

// If message has media, resolve the URL from Meta API
if (['image', 'audio', 'video', 'document'].includes(type)) {
  const mediaObj = message[type];
  const mediaId = mediaObj?.id;

  if (mediaId) {
    try {
      const supabaseUrl = "https://ibyterftfrqgkhktkaeg.supabase.co";
      const serviceKey = "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImlieXRlcmZ0ZnJxZ2toa3RrYWVnIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3ODQ0OTgwMywiZXhwIjoyMDk0MDI1ODAzfQ.9ObjlZum0x9XQuZYVxBZJGzLKA_jbaz1wqxC4lMj_M8";
      const channelId = "4886443e-4996-4d2a-83e1-d96f503e1a28";

      const channelsResp = await $helpers.httpRequest({
        method: 'GET',
        url: `${supabaseUrl}/rest/v1/channels?id=eq.${channelId}&select=access_token`,
        headers: {
          'apikey': serviceKey,
          'Authorization': `Bearer ${serviceKey}`
        }
      });

      const accessToken = channelsResp?.[0]?.access_token;

      if (accessToken) {
        const mediaResp = await $helpers.httpRequest({
          method: 'GET',
          url: `https://graph.facebook.com/v20.0/${mediaId}`,
          headers: {
            'Authorization': `Bearer ${accessToken}`
          }
        });

        mediaUrl = mediaResp?.url || null;
      }
    } catch (e) {
      console.error('Error resolving Meta media URL:', e.message);
    }
  }

  if (!content) {
    if (type === 'image') content = '[Imagem]';
    else if (type === 'audio') content = '[Áudio]';
    else if (type === 'video') content = '[Vídeo]';
    else if (type === 'document') content = '[Documento]';
    else content = '[Mídia]';
  }
}

return [{
  json: {
    whatsapp_msg_id: msgId,
    phone: phone,
    contact_name: contactName,
    direction: 'in',
    content: content,
    content_type: type,
    media_url: mediaUrl,
    timestamp: new Date(parseInt(message.timestamp) * 1000).toISOString(),
    raw_payload: body
  }
}];

const rawSettings = $('Fetch AI Settings').first()?.json || {};
let parsedSettings = {};
try {
  parsedSettings = JSON.parse(rawSettings.system_prompt || '{}');
} catch (e) {
  parsedSettings = rawSettings;
}

// Retrieve contact tags
let contact = {};
try {
  contact = $('Upsert Contact').first().json;
} catch(e) {
  try {
    contact = $input.first().json; // fallback
  } catch(err) {}
}

const tags = contact.tags || [];
const isPausedByTag = tags.includes('IA Inativa');

// Read columns from parsed system_prompt JSON
const isEnabledGlobal = parsedSettings.is_enabled ?? rawSettings.is_enabled ?? true;
const systemPrompt = parsedSettings.system_prompt ?? rawSettings.system_prompt ?? '';
const negativePrompt = parsedSettings.negative_prompt ?? rawSettings.negative_prompt ?? '';
const apiKey = parsedSettings.api_key ?? rawSettings.api_key ?? '';
const model = parsedSettings.model ?? rawSettings.model ?? 'gpt-4o-mini';
const temperature = rawSettings.temperature ?? parsedSettings.temperature ?? 0.7;
const pausePhrases = rawSettings.pause_trigger_phrases ?? parsedSettings.pause_trigger_phrases ?? [];

// Find message info dynamically
let msgText = '';
let direction = 'in';
let phone = contact.phone || '';

try {
  const parsed = $('Parse Meta Payload').first().json;
  msgText = parsed.content || '';
  direction = parsed.direction || 'in';
  if (!phone) phone = parsed.phone || '';
} catch(e) {}

const isInbound = direction === 'in';

// Check pause trigger phrases
const matchedPhrase = pausePhrases.find(p => p && msgText.toLowerCase().includes(p.toLowerCase()));

let pauseBot = false;
let runAi = false;
let reason = '';

if (!isEnabledGlobal) {
  reason = 'AI is disabled globally';
} else if (!isInbound) {
  reason = 'Message is outbound';
} else if (isPausedByTag) {
  reason = 'AI is paused for this contact (IA Inativa tag present)';
} else if (matchedPhrase) {
  pauseBot = true;
  reason = `AI paused by trigger phrase: "${matchedPhrase}"`;
} else {
  runAi = true;
  reason = 'All checks passed, running AI';
}

const updatedTags = isPausedByTag ? tags : [...tags, 'IA Inativa'];

return [{
  json: {
    run_ai: runAi,
    pause_bot: pauseBot,
    reason: reason,
    contact_id: contact.id,
    phone: phone,
    channel_id: contact.channel_id || rawSettings.channel_id,
    user_message: msgText,
    system_prompt: systemPrompt,
    negative_prompt: negativePrompt,
    api_key: apiKey,
    model: model,
    temperature: temperature,
    updated_tags: updatedTags
  }
}];

const msgs = $input.all().map(item => item.json);
const inboundMsgs = msgs.filter(m => m.direction === 'in');
const routerData = $('AI Routing Decision').first().json;
const welcomeMessage = routerData.welcome_message || '';

if (inboundMsgs.length <= 1 && welcomeMessage.trim() !== '') {
  return [{
    json: {
      is_welcome: true,
      contact_id: routerData.contact_id,
      phone: routerData.phone,
      channel_id: routerData.channel_id,
      content: welcomeMessage
    }
  }];
}

msgs.reverse();

const historyText = msgs.map(m => {
  const role = m.direction === 'in' ? 'USER' : 'ASSISTANT';
  return `${role}: ${m.content || ''}`;
}).join('\n\n');

const systemContent = `${routerData.system_prompt}\n\nRESTRISÇÕES IMPORTANTES (O QUE NUNCA FAZER):\n${routerData.negative_prompt}`;

const systemMessage = `${systemContent}\n\nCONVERSATION HISTORY:\n${historyText}`;

return [{
  json: {
    is_welcome: false,
    api_key: routerData.api_key,
    model: routerData.model,
    temperature: routerData.temperature,
    chatInput: routerData.user_message,
    systemMessage: systemMessage,
    contact_id: routerData.contact_id,
    phone: routerData.phone,
    channel_id: routerData.channel_id
  }
}];

const resp = $input.first().json;
const answer = resp.output || resp.text || resp.content || JSON.stringify(resp);
const inputData = $('Format Prompt & History').first().json;
return [{
  json: {
    contact_id: inputData.contact_id,
    phone: inputData.phone,
    channel_id: inputData.channel_id,
    content: answer
  }
}];

